func UpdatedAtGTE(v time.Time) predicate.ItemVersion {
	return predicate.ItemVersion(sql.FieldGTE(FieldUpdatedAt, v))
}

// UpdatedAtLT applies the LT predicate on the "updated_at" field.
func UpdatedAtLT(v time.Time) predicate.ItemVersion {
	return predicate.ItemVersion(sql.FieldLT(FieldUpdatedAt, v))
}

// UpdatedAtLTE applies the LTE predicate on the "updated_at" field.
func UpdatedAtLTE(v time.Time) predicate.ItemVersion {
	return predicate.ItemVersion(sql.FieldLTE(FieldUpdatedAt, v))
}

// HasItem applies the HasEdge predicate on the "item" edge.
func HasItem() predicate.ItemVersion {
	return predicate.ItemVersion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ItemTable, ItemColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasItemWith applies the HasEdge predicate on the "item" edge with a given conditions (other predicates).
func HasItemWith(preds ...predicate.MarketplaceItem) predicate.ItemVersion {
	return predicate.ItemVersion(func(s *sql.Selector) {
		step := newItemStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ItemVersion) predicate.ItemVersion {
	return predicate.ItemVersion(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ItemVersion) predicate.ItemVersion {
	return predicate.ItemVersion(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ItemVersion) predicate.ItemVersion {
	return predicate.ItemVersion(sql.NotPredicates(p))
}
